113	   * record is keyed by the provider-specific metadata key.
114	   * ```ts
115	   * {
116	   * "openai": {
117	   * "style": "vivid"
118	   * }
119	   * }
120	   * ```
121	   */
122	  providerOptions?: ProviderOptions;
123	
124	  /**
125	   * Maximum number of retries per image model call. Set to 0 to disable retries.
126	   *
127	   * @default 2
128	   */
129	  maxRetries?: number;
130	
131	  /**
132	   * Abort signal.
133	   */
134	  abortSignal?: AbortSignal;
135	
136	  /**
137	   * Additional headers to include in the request.
138	   * Only applicable for HTTP-based providers.
139	   */
140	  headers?: Record<string, string>;
141	}): Promise<GenerateImageResult> {
142	  const model = resolveImageModel(modelArg);
143	
144	  const headersWithUserAgent = withUserAgentSuffix(
145	    headers ?? {},
146	    `ai/${VERSION}`,
147	  );
148	
149	  const { retry } = prepareRetries({
150	    maxRetries: maxRetriesArg,
151	    abortSignal,
152	  });
153	
154	  // default to 1 if the model has not specified limits on
155	  // how many images can be generated in a single call
156	  const maxImagesPerCallWithDefault =
157	    maxImagesPerCall ?? (await invokeModelMaxImagesPerCall(model)) ?? 1;
158	
159	  // parallelize calls to the model:
160	  const callCount = Math.ceil(n / maxImagesPerCallWithDefault);
161	  const callImageCounts = Array.from({ length: callCount }, (_, i) => {
162	    if (i < callCount - 1) {
163	      return maxImagesPerCallWithDefault;
164	    }
165	
166	    const remainder = n % maxImagesPerCallWithDefault;
167	    return remainder === 0 ? maxImagesPerCallWithDefault : remainder;
168	  });
169	
170	  const results = await Promise.all(
171	    callImageCounts.map(async callImageCount =>
172	      retry(() => {
173	        const { prompt, files, mask } = normalizePrompt(promptArg);
174	
175	        return model.doGenerate({
176	          prompt,
177	          files,
178	          mask,
179	          n: callImageCount,
180	          abortSignal,
181	          headers: headersWithUserAgent,
182	          size,
183	          aspectRatio,
184	          seed,
185	          providerOptions: providerOptions ?? {},
186	        });
187	      }),
188	    ),
189	  );
190	
191	  // collect result images, warnings, and response metadata
192	  const images: Array<DefaultGeneratedFile> = [];
193	  const warnings: Array<Warning> = [];
194	  const responses: Array<ImageModelResponseMetadata> = [];
195	  const providerMetadata: ImageModelV3ProviderMetadata = {};
196	  let totalUsage: ImageModelUsage = {
197	    inputTokens: undefined,
198	    outputTokens: undefined,
199	    totalTokens: undefined,
200	  };
201	  for (const result of results) {
202	    images.push(
203	      ...result.images.map(
204	        image =>
205	          new DefaultGeneratedFile({
206	            data: image,
207	            mediaType:
208	              detectMediaType({
209	                data: image,
210	                signatures: imageMediaTypeSignatures,
211	              }) ?? 'image/png',
212	          }),
213	      ),
214	    );
215	    warnings.push(...result.warnings);
216	
217	    if (result.usage != null) {
218	      totalUsage = addImageModelUsage(totalUsage, result.usage);
219	    }
220	
221	    if (result.providerMetadata) {
222	      for (const [providerName, metadata] of Object.entries<{
223	        images: unknown;
224	      }>(result.providerMetadata)) {
225	        if (providerName === 'gateway') {
226	          const currentEntry = providerMetadata[providerName];
227	          if (currentEntry != null && typeof currentEntry === 'object') {
228	            providerMetadata[providerName] = {
229	              ...(currentEntry as object),
230	              ...metadata,
231	            } as ImageModelV3ProviderMetadata[string];
232	          } else {
233	            providerMetadata[providerName] =
234	              metadata as ImageModelV3ProviderMetadata[string];
235	          }
236	          const imagesValue = (
237	            providerMetadata[providerName] as { images?: unknown }
238	          ).images;
239	          if (Array.isArray(imagesValue) && imagesValue.length === 0) {
240	            delete (providerMetadata[providerName] as { images?: unknown })
241	              .images;
242	          }
243	        } else {
244	          providerMetadata[providerName] ??= { images: [] };
245	          providerMetadata[providerName].images.push(
246	            ...result.providerMetadata[providerName].images,
247	          );
248	        }
249	      }
250	    }
251	
252	    responses.push(result.response);
253	  }
254	
255	  logWarnings({ warnings, provider: model.provider, model: model.modelId });
256	
257	  if (!images.length) {
258	    throw new NoImageGeneratedError({ responses });
259	  }
260	
261	  return new DefaultGenerateImageResult({
262	    images,
263	    warnings,
264	    responses,
265	    providerMetadata,
266	    usage: totalUsage,
267	  });
268	}
