20	export class GatewayImageModel implements ImageModelV3 {
21	  readonly specificationVersion = 'v3' as const;
22	  // Set a very large number to prevent client-side splitting of requests
23	  readonly maxImagesPerCall = Number.MAX_SAFE_INTEGER;
24	
25	  constructor(
26	    readonly modelId: string,
27	    private readonly config: GatewayConfig & {
28	      provider: string;
29	      o11yHeaders: Resolvable<Record<string, string>>;
30	    },
31	  ) {}
32	
33	  get provider(): string {
34	    return this.config.provider;
35	  }
36	
37	  async doGenerate({
38	    prompt,
39	    n,
40	    size,
41	    aspectRatio,
42	    seed,
43	    files,
44	    mask,
45	    providerOptions,
46	    headers,
47	    abortSignal,
48	  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
49	    Awaited<ReturnType<ImageModelV3['doGenerate']>>
50	  > {
51	    const resolvedHeaders = await resolve(this.config.headers());
52	    try {
53	      const {
54	        responseHeaders,
55	        value: responseBody,
56	        rawValue,
57	      } = await postJsonToApi({
58	        url: this.getUrl(),
59	        headers: combineHeaders(
60	          resolvedHeaders,
61	          headers ?? {},
62	          this.getModelConfigHeaders(),
63	          await resolve(this.config.o11yHeaders),
64	        ),
65	        body: {
66	          prompt,
67	          n,
68	          ...(size && { size }),
69	          ...(aspectRatio && { aspectRatio }),
70	          ...(seed && { seed }),
71	          ...(providerOptions && { providerOptions }),
72	          ...(files && {
73	            files: files.map(file => maybeEncodeImageFile(file)),
74	          }),
75	          ...(mask && { mask: maybeEncodeImageFile(mask) }),
76	        },
77	        successfulResponseHandler: createJsonResponseHandler(
78	          gatewayImageResponseSchema,
79	        ),
80	        failedResponseHandler: createJsonErrorResponseHandler({
81	          errorSchema: z.any(),
82	          errorToMessage: data => data,
83	        }),
84	        ...(abortSignal && { abortSignal }),
85	        fetch: this.config.fetch,
86	      });
87	
88	      return {
89	        images: responseBody.images, // Always base64 strings from server
90	        warnings: responseBody.warnings ?? [],
91	        providerMetadata:
92	          responseBody.providerMetadata as ImageModelV3ProviderMetadata,
93	        response: {
94	          timestamp: new Date(),
95	          modelId: this.modelId,
96	          headers: responseHeaders,
97	        },
98	        ...(responseBody.usage != null && {
99	          usage: {
100	            inputTokens: responseBody.usage.inputTokens ?? undefined,
101	            outputTokens: responseBody.usage.outputTokens ?? undefined,
102	            totalTokens: responseBody.usage.totalTokens ?? undefined,
103	          },
104	        }),
105	      };
106	    } catch (error) {
107	      throw await asGatewayError(error, await parseAuthMethod(resolvedHeaders));
108	    }
109	  }
110	
111	  private getUrl() {
112	    return `${this.config.baseURL}/image-model`;
113	  }
114	
115	  private getModelConfigHeaders() {
116	    return {
117	      'ai-image-model-specification-version': '3',
118	      'ai-model-id': this.modelId,
119	    };
120	  }
121	}
122	
123	function maybeEncodeImageFile(file: ImageModelV3File) {
124	  if (file.type === 'file' && file.data instanceof Uint8Array) {
125	    return {
126	      ...file,
127	      data: convertUint8ArrayToBase64(file.data),
128	    };
129	  }
130	  return file;
131	}
132	
133	const providerMetadataEntrySchema = z
134	  .object({
135	    images: z.array(z.unknown()).optional(),
136	  })
137	  .catchall(z.unknown());
138	
139	const gatewayImageWarningSchema = z.discriminatedUnion('type', [
140	  z.object({
141	    type: z.literal('unsupported'),
142	    feature: z.string(),
143	    details: z.string().optional(),
144	  }),
145	  z.object({
146	    type: z.literal('compatibility'),
147	    feature: z.string(),
148	    details: z.string().optional(),
149	  }),
150	  z.object({
151	    type: z.literal('other'),
152	    message: z.string(),
153	  }),
154	]);
155	
156	const gatewayImageUsageSchema = z.object({
157	  inputTokens: z.number().nullish(),
158	  outputTokens: z.number().nullish(),
159	  totalTokens: z.number().nullish(),
160	});
161	
162	const gatewayImageResponseSchema = z.object({
163	  images: z.array(z.string()), // Always base64 strings over the wire
164	  warnings: z.array(gatewayImageWarningSchema).optional(),
165	  providerMetadata: z
166	    .record(z.string(), providerMetadataEntrySchema)
167	    .optional(),
168	  usage: gatewayImageUsageSchema.optional(),
169	});
