  n: callImageCount,
  abortSignal,
  headers: headersWithUserAgent,
  size,
  aspectRatio,
  seed,
  providerOptions: providerOptions ?? {},
})
```

**Input prompt types supported:**
```typescript
export type GenerateImagePrompt =
  | string
  | {
      images: Array<DataContent>;
      text?: string;
      mask?: DataContent;
    };
```

This enables:
- Simple text prompts: `"a sunny beach"`
- Image editing: `{ images: [imageData], text: "make it darker" }`
- Image variations: `{ images: [imageData] }`
- Inpainting: `{ images: [imageData], mask: maskData }`

---

### **4. PROVIDER PACKAGE EXPORTS (packages/provider/)**

**File:** `/packages/provider/src/index.ts`

Exports image-model related types through:
