  zodSchema(
    z.object({
      /**
       * The visual style of the generated pixel art.
       */
      style: z.enum(['pixel', 'retro', '8bit']).optional(),

      /**
       * The density of pixels in the generated image.
       */
      pixelDensity: z.number().optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<
  typeof pixelArtImageModelOptionsSchema
>;

// Minimal response schema focused on what is needed for the implementation.
const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

const pixelArtErrorSchema = z.object({
  message: z.string().optional(),
  detail: z.any().optional(),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: error => {
    const parsed = pixelArtErrorSchema.safeParse(error);
    if (!parsed.success) return 'Unknown PixelArt error';
    const { message, detail } = parsed.data;
    if (typeof detail === 'string') return detail;
    return message ?? 'Unknown PixelArt error';
  },
});

